import React from "react";
import styled from "styled-components";
import { Link } from "react-router-dom";
import { FaArrowRight } from "react-icons/fa";

/**
 * Hero component with Meta-inspired design
 * @returns {JSX.Element} Hero component
 */
const Hero = () => {
  return (
    <HeroWrapper>
      <HeroContainer>
        <HeroOverlay>
          <HeroContent>
            <HeroTextContent>
              <HeroTitle>Creating sustainable change in Tanzania</HeroTitle>
              <HeroDescription>
                We work with local communities to develop solutions that address the root causes of 
                poverty and create lasting positive change.
              </HeroDescription>
              <HeroButtons>
                <PrimaryButton to="/donate">Donate Now</PrimaryButton>
                <SecondaryButton to="/our-work">
                  Learn More
                  <ButtonIcon>
                    <FaArrowRight />
                  </ButtonIcon>
                </SecondaryButton>
              </HeroButtons>
            </HeroTextContent>
          </HeroContent>
        </HeroOverlay>
      </HeroContainer>
    </HeroWrapper>
  );
};

// Styled components with 2 spaces indentation
const HeroWrapper = styled.div`
  width: 100%;
  padding: 0 20px;
  margin: 20px auto;
  max-width: 1240px;

  @media (max-width: 768px) {
    padding: 0 10px;
    margin: 10px auto;
  }
`;
const HeroContainer = styled.section`
  position: relative;
  background-image: url("/images/hero/hero-image.jpg");
  background-size: cover;
  background-position: center;
  width: 100%;
  height: 600px;
  overflow: hidden;
  border-radius: 12px;
  margin: 0 20px;
  max-width: calc(100% - 40px);

  @media (max-width: 768px) {
    height: 500px;
    margin: 0 10px;
    max-width: calc(100% - 20px);
  }
`;

const HeroOverlay = styled.div`
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(rgba(0, 0, 0, 0.4), rgba(0, 0, 0, 0.7));
  display: flex;
  align-items: center;
`;

const HeroContent = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  width: 100%;
  position: relative;
  z-index: 2;
`;

const HeroTextContent = styled.div`
  max-width: 600px;
  color: white;

  @media (max-width: 1024px) {
    max-width: 100%;
    text-align: center;
  }
`;

const HeroTitle = styled.h1`
  font-size: 42px;
  font-weight: 700;
  line-height: 1.1;
  margin-bottom: 20px;
  color: white;

  @media (max-width: 768px) {
    font-size: 32px;
  }
`;

const HeroDescription = styled.p`
  font-size: 18px;
  line-height: 1.5;
  margin-bottom: 32px;
  color: rgba(255, 255, 255, 0.9);
`;

const HeroButtons = styled.div`
  display: flex;
  gap: 16px;

  @media (max-width: 1024px) {
    justify-content: center;
  }

  @media (max-width: 480px) {
    flex-direction: column;
  }
`;

const Button = styled(Link)`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 12px 24px;
  font-size: 16px;
  font-weight: 600;
  border-radius: 100px;
  text-decoration: none;
  transition: transform 0.2s ease, box-shadow 0.2s ease;

  &:hover {
    transform: translateY(-2px);
  }

  &:active {
    transform: translateY(0);
  }
`;

const PrimaryButton = styled(Button)`
  background-color: var(--primary-color);
  color: white;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);

  &:hover {
    background-color: var(--secondary-color);
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.15);
    color: white;
    transform: translateY(-2px);
    transition: all 0.3s ease;
  }
`;

const SecondaryButton = styled(Button)`
  background-color: rgba(255, 255, 255, 0.9);
  color: var(--primary-color);

  &:hover {
    background-color: white;
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.1);
  }
`;

const ButtonIcon = styled.span`
  margin-left: 8px;
  display: inline-flex;
  font-size: 14px;
  transition: transform 0.2s ease;

  ${SecondaryButton}:hover & {
    transform: translateX(4px);
  }
`;

export default Hero;
